import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val adj = Array.ofDim[Array[(Int, Long, Long)]](n.toInt)
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val s = edge(2)
    val e = edge(3)
    adj(u) = adj(u) :+ (v, s, e)
  }

  val INF = 1e18.toLong
  val distance = Array.fill(n.toInt)(INF)
  distance(0) = 0

  val pq = PriorityQueue[(Long, Int)]()
  pq += (0, 0)

  while (pq.nonEmpty) {
    val (current_time, u) = pq.dequeue()
    if (u == n - 1) return current_time
    if (current_time > distance(u)) {
      // Skip this entry as a better time was already found
    } else {
      for (edge <- adj(u)) {
        val (v, s, e) = edge
        val earliest_time = math.max(current_time, s)
        if (earliest_time <= e) {
          val new_time = earliest_time + 1
          if (new_time < distance(v)) {
            distance(v) = new_time
            pq += (new_time, v)
          }
        }
      }
    }
  }

  -1
}
